//! Contract Lifecycle Manager for Xergon protocol contracts.
//!
//! Manages the full lifecycle of ErgoScript contracts on the Xergon network:
//! - Template system with built-in contract templates (6 Xergon contracts)
//! - Deployment pipeline (compile, deploy, track)
//! - Upgrade system with backward compatibility checks and rollback
//! - Contract parameterization and validation
//! - Contract registry with dependency graph
//! - Contract monitoring (age, interactions, storage rent estimation)

use axum::{
    extract::{Path, State},
    http::StatusCode,
    response::{IntoResponse, Json, Response},
    routing::{get, post},
    Router,
};
use dashmap::DashMap;
use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::sync::atomic::{AtomicU64, Ordering};
use std::sync::Arc;
use std::time::{SystemTime, UNIX_EPOCH};
use tracing::{info, warn};

// ---------------------------------------------------------------------------
// 1. CORE TYPES
// ---------------------------------------------------------------------------

/// Deployment status of a contract.
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq)]
#[serde(rename_all = "lowercase")]
pub enum DeploymentStatus {
    Pending,
    Compiling,
    Deploying,
    Deployed,
    Failed,
    Upgraded,
}

/// Parameter types supported by ErgoScript contracts.
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub enum ParameterType {
    String,
    Int,
    Long,
    BigInt,
    Boolean,
    Coll,
    GroupElement,
    ErgoAddress,
}

/// A parameter definition for a contract template.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ContractParameter {
    pub name: String,
    pub param_type: ParameterType,
    pub default_value: String,
    pub description: String,
    pub required: bool,
}

/// A contract template with parameterized ErgoScript source.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ContractTemplate {
    pub name: String,
    pub version: String,
    pub source_code: String,
    pub compiled_hex: String,
    pub parameters: Vec<ContractParameter>,
    pub description: String,
}

/// A contract deployment record.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ContractDeployment {
    pub id: String,
    pub template_name: String,
    pub template_version: String,
    pub parameters: HashMap<String, String>,
    pub compiled_hex: String,
    pub box_id: String,
    pub tx_id: String,
    pub deployed_at: u64,
    pub status: DeploymentStatus,
    pub error: Option<String>,
}

/// Information about a registered (deployed) contract.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ContractInfo {
    pub name: String,
    pub version: String,
    pub ergo_tree_hex: String,
    pub parameters: HashMap<String, String>,
    pub deployed_at: u64,
    pub box_id: String,
    pub template_name: String,
    pub interaction_count: u64,
    pub last_updated: u64,
}

/// An upgrade request for an existing contract.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct UpgradeRequest {
    pub contract_name: String,
    pub from_version: String,
    pub to_version: String,
    pub migration_script: String,
    pub rollback_plan: String,
    pub dry_run: bool,
}

/// Result of an upgrade validation.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct UpgradeValidation {
    pub valid: bool,
    pub contract_name: String,
    pub from_version: String,
    pub to_version: String,
    pub register_compatible: bool,
    pub warnings: Vec<String>,
    pub errors: Vec<String>,
}

/// Result of a contract upgrade.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct UpgradeResult {
    pub success: bool,
    pub contract_name: String,
    pub previous_version: String,
    pub new_version: String,
    pub tx_id: String,
    pub dry_run: bool,
    pub error: Option<String>,
}

/// Rollback request.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RollbackRequest {
    pub contract_name: String,
    pub target_version: String,
    pub reason: String,
}

/// Monitoring status for a deployed contract.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ContractMonitorEntry {
    pub contract_name: String,
    pub box_id: String,
    pub deployed_at: u64,
    pub age_hours: f64,
    pub interaction_count: u64,
    pub last_updated: u64,
    pub storage_rent_estimate_nanoerg: u64,
    pub status: String,
    pub alerts: Vec<String>,
}

/// Dependency edge in the contract dependency graph.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ContractDependency {
    pub from_contract: String,
    pub to_contract: String,
    pub relationship: String,
}

